async def evaluate(persona, stimulus, axes):
    prompt = f"""당신은 소비자 반응 평가 전문가입니다.
[자극물] 유형: {stimulus.type} / 내용: {stimulus.text}
[페르소나] {persona.age} {persona.gender} {persona.job}
           특성: {', '.join(persona.traits)}
[평가축] {', '.join(axes)}
각 축에 0-100점과 근거를 JSON으로 응답하세요."""

    response = await claude.messages.create(
        model="claude-sonnet-4-20250514",
        max_tokens=600,
        messages=[{"role": "user", "content": prompt}],
    )
    return parse_evaluation(response.content)

def _get_trend_adjustment(self, request):
    """RAG에서 트렌드 검색 → 축별 보정값 계산"""
    if not self._ensure_rag_loaded():
        return {}

    query = f"{request.stimulus_type.value} {request.stimulus[:50]}"
    results = self._rag.search_trends(query, n_results=3)

    documents = results.get("documents", [[]])[0]
    if not documents:
        return {}

    trend_count = len(documents)
    base_boost  = min(trend_count * 3, 10)

    trend_text = " ".join(documents).lower()
    positive   = sum(1 for k in ["증가", "상승", "인기", "성장"] if k in trend_text)
    negative   = sum(1 for k in ["감소", "하락", "위축", "부진"] if k in trend_text)
    sentiment  = (positive - negative) * 2

    return {
        axis: base_boost + sentiment
        for axis in ["호감도", "구매의향", "관심도", "사용의향",
                     "참여의향", "클릭의향", "추천의향"]
    }

AGE_RESPONSE_TRAITS = {
    AgeGroup.TEENS: {
        "central_tendency":     0.15,  # 극단 회피 약함
        "acquiescence":         0.25,
        "social_desirability":  0.30,
        "straight_lining":      0.10,
    },
    AgeGroup.FIFTIES: {
        "central_tendency":     0.45,  # 극단 회피 강함
        "acquiescence":         0.50,
        "social_desirability":  0.55,
        "straight_lining":      0.35,
    },
}

def _apply_human_biases(self, persona, score, question):
    traits = AGE_RESPONSE_TRAITS[persona.age_group]

    # 1. 극단 회피
    if random.random() < traits["central_tendency"]:
        score = score * 0.7 + 50 * 0.3

    # 2. 묵종 편향
    if random.random() < traits["acquiescence"]:
        score = min(100, score + random.uniform(3, 8))

    # 3. 사회적 바람직성
    if self._is_socially_sensitive(question):
        if random.random() < traits["social_desirability"]:
            score = min(100, score + random.uniform(5, 12))

    # 4. 응답 노이즈
    score += random.gauss(0, 5)
    return max(0, min(100, score))
